comparisons.rust:
struct CountUp { current: i32, max: i32 }

impl Iterator for CountUp {
    type Item = i32;
    fn next(&mut self) -> Option<i32> {
        if self.current < self.max {
            let val = self.current;
            self.current += 1;
            Some(val)
        } else { None }
    }
}

